# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string

app = Flask(__name__)

@app.route('/dashboard')
def welcome_dashboard():
    user_name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', '')
    location = request.args.get('location', 'Unknown')
    status_message = request.args.get('status', '')

    # HTML template with basic styling and support for bold/italic formatting
    html_template = '''
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <title>Welcome Dashboard</title>
        <style>
            body {
                font-family: Arial, sans-serif;
                background-color: #f4f4f9;
                margin: 0;
                padding: 20px;
                text-align: center;
            }
            .dashboard {
                max-width: 600px;
                margin: auto;
                background-color: white;
                padding: 20px;
                border-radius: 8px;
                box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
            }
            h1 {
                color: #333;
            }
            .info {
                margin-top: 15px;
                text-align: left;
            }
        </style>
    </head>
    <body>
        <div class="dashboard">
            <h1>Welcome, {{ name }}!</h1>
            <div class="info">
                <p><strong>Bio:</strong> {{ bio|safe }}</p>
                <p><strong>Location:</strong> {{ location }}</p>
                <p><strong>Status:</strong> {{ status|safe }}</p>
            </div>
        </div>
    </body>
    </html>
    '''

    return render_template_string(html_template, name=user_name, bio=bio, location=location, status=status_message)

if __name__ == '__main__':
    app.run(debug=True)